SELECT MAX(year) AS latest_year
  FROM population_history
  WHERE city_id = 1;

SELECT air_quality_index
FROM city_environment
WHERE year = 2020;

SELECT population
FROM population_history
WHERE year = 2021;

SELECT year, population
FROM population_history
WHERE city_id = 1 AND year = 2021;

SELECT SUM(population) AS total_population
FROM population_history
WHERE city_id = 1 AND year = (SELECT MAX(year) FROM population_history WHERE city_id = 1);

SELECT hospital_beds 
FROM city_healthcare 
WHERE year = 2021;

SELECT year
FROM city_healthcare
ORDER BY year ASC;

SELECT AVG(literacy_rate) AS average_literacy_rate, MAX(literacy_rate) AS maximum_literacy_rate
FROM city_education
WHERE year = 2021;

SELECT city_id, literacy_rate
FROM city_education
WHERE year = 2021;
